    {
      "id": "staff",
      "name": "Staff",
      "description": "Can manage availability and update booking status, cannot delete services"
    },
    {
      "id": "customer",
      "name": "Customer",
      "description": "Can browse active services and time slots, create and manage own bookings"
    }
  ],
  "coverage_matrix": [
    {
      "feature": "Hybrid Tenancy",
      "status": "covered",
      "notes": "Implemented via two route groups: /api/:organization/ and /api/customer/"
