    {
      "feature": "Service Management",
      "status": "covered",
      "notes": "Implemented via services model with status active/draft/inactive"
    },
    {
      "feature": "Staff Members",
      "status": "covered",
      "notes": "Implemented via staff_members model"
    },
    {
      "feature": "Time Slot Management",
      "status": "covered",
      "notes": "Implemented via time_slots model with available boolean"
    },
    {
      "feature": "Customer Booking",
      "status": "covered",
      "notes": "Implemented via bookings model referencing time_slot"
    },
    {
      "feature": "Booking Lifecycle",
      "status": "covered",
      "notes": "Implemented via bookings status transitions and policy checks"
    },
    {
      "feature": "Cross-Tenant Isolation",
      "status": "covered",
      "notes": "Enforced via organization_id scoping and current_user scoping"
    },
    {
      "feature": "Draft/Inactive Hiding",
      "status": "covered",
      "notes": "Enforced via ServiceScope and TimeSlotScope on customer route"
    }
  ],
  "hints_for_planner": [
    "Add organization_id to time_slots model to satisfy multi-tenant scoping.",
    "Implement custom scopes for Service, TimeSlot, and Booking to handle customer-route filtering.",
    "Ensure customer route uses current_user scoping for bookings."
  ],
  "updated_at": "2026-07-16T20:35:00Z"
